dream_query.sdl_delta:
extend type Mutation {
  """Upsert a product — creates if no id is supplied, updates otherwise."""
  upsertProduct(input: UpsertProductInput!): UpsertProductPayload!
}

input UpsertProductInput {
  id: ID
  title: String!
  descriptionHtml: String
  priceCents: Int!
  currency: String!
  inventoryQuantity: Int = 0
  tags: [String!] = []
}

type UpsertProductPayload {
  product: Product!
  created: Boolean!
}

type Product @key(fields: "id") {
  id: ID!
  title: String!
  descriptionHtml: String
  priceCents: Int!
  currency: String!
  inventoryQuantity: Int!
  tags: [String!]!
  updatedAt: DateTime!
}

extend type Subscription {
  productUpdated(id: ID!): Product! @edfs__kafkaPublish(topic: "understudy.events.productUpdated")
}

scalar DateTime
